# ── Singleton routing engine ─────────────────────────
_engine = RoutingEngine()

# ── Route table ────────────────────────────────────
_ROUTES = {
    ('GET',  '/health'): _health_handler,
    ('POST', '/plan'):    _plan_handler,
    ('POST', '/update'):  _update_handler,
}

# ── _parse_body ────────────────────────────────────
def _parse_body(body: bytes) -> TravelInput | dict:
    try:
        d = json.loads(body.decode('utf-8'))
    except (ValueError, UnicodeDecodeError):
        return {'error': 'Invalid JSON'}
    try:
        return TravelInput.from_dict(d)   # POST /plan
    except Exception:
        return d                         # dict for /update

# ── _plan_handler ──────────────────────────────────
def _plan_handler(body) -> tuple[dict, int]:
    parsed = _parse_body(body)
    if isinstance(parsed, dict) and 'error' in parsed:
        return parsed, 400

    inp = parsed   # TravelInput
    vresult = validate(inp)
    if vresult.status == FAILED:
        return vresult.to_dict(), 400

    output = _engine.plan(inp)
    return output.to_dict(), 200

# ── _update_handler ────────────────────────────────
def _update_handler(body) -> tuple[dict, int]:
    d = json.loads(body.decode('utf-8'))
    base_dict  = d.get('base')
    input_dict = d.get('input')
    if not base_dict or not input_dict:
        return {'error': "Missing 'base' and/or 'input'"}, 400

    try:
        base = TravelOutput.from_dict(base_dict)
        inp  = TravelInput.from_dict(input_dict)
    except Exception as e:
        return {'error': str(e)}, 400

    vresult = validate(inp)
    if vresult.status == FAILED:
        return vresult.to_dict(), 400

    updated = _engine.update(base, inp)
    return updated.to_dict(), 200

